// ═══════════════════════════════════════════
// INVOICE MODULE
// ═══════════════════════════════════════════

let invoiceItems = [];
let invItemIdCounter = 0;

function newInvoiceItemId() {
  invItemIdCounter += 1;
  return 'item_' + invItemIdCounter;
}

function initInvoiceDefaults() {
  if (invoiceItems.length === 0) {
    invoiceItems.push({ id: newInvoiceItemId(), desc: '', qty: 1, price: 0 });
  }
  const today = new Date().toISOString().split('T')[0];
  const due = new Date();
  due.setDate(due.getDate() + 30);
  if (document.getElementById('invDate') && !document.getElementById('invDate').value) {
    document.getElementById('invDate').value = today;
  }
  if (document.getElementById('invDueDate') && !document.getElementById('invDueDate').value) {
    document.getElementById('invDueDate').value = due.toISOString().split('T')[0];
  }
}

function renderInvoiceItemsForm() {
  const isAr = currentLang === 'ar';
  const container = document.getElementById('invItemsList');
  if (!container) return;
  container.innerHTML = invoiceItems.map((it, i) => `
    <div class="inv-item-row">
      <div class="field">
        <label>${isAr ? 'الوصف' : 'Description'}</label>
        <input value="${escapeAttr(it.desc)}" placeholder="${isAr ? 'الخدمة / المنتج' : 'Service / product'}"
          oninput="updateInvoiceItem('${it.id}','desc',this.value)">
      </div>
      <div class="field">
        <label>${isAr ? 'الكمية' : 'Qty'}</label>
        <input type="number" min="0" step="any" value="${it.qty}"
          oninput="updateInvoiceItem('${it.id}','qty',this.value)">
      </div>
      <div class="field">
        <label>${isAr ? 'السعر' : 'Price'}</label>
        <input type="number" min="0" step="any" value="${it.price}"
          oninput="updateInvoiceItem('${it.id}','price',this.value)">
      </div>
      <div class="field">
        <label>${isAr ? 'المجموع' : 'Total'}</label>
        <input id="line-total-${it.id}" readonly class="readonly-field" value="${(it.qty * it.price).toFixed(3)}">
      </div>
      <button type="button" class="inv-item-del" onclick="removeInvoiceItem('${it.id}')" title="${isAr ? 'حذف' : 'Remove'}">×</button>
    </div>`).join('');
}

function escapeAttr(str) {
  return String(str || '').replace(/"/g, '&quot;');
}

function addInvoiceItem() {
  invoiceItems.push({ id: newInvoiceItemId(), desc: '', qty: 1, price: 0 });
  renderInvoiceItemsForm();
  updateInvoicePreview();
}

function removeInvoiceItem(id) {
  if (invoiceItems.length <= 1) {
    showToast(currentLang === 'ar' ? 'يجب أن يحتوي على بند واحد على الأقل' : 'At least one item is required');
    return;
  }
  invoiceItems = invoiceItems.filter(it => it.id !== id);
  renderInvoiceItemsForm();
  updateInvoicePreview();
}

function updateInvoiceItem(id, field, value) {
  const item = invoiceItems.find(it => it.id === id);
  if (!item) return;
  if (field === 'desc') {
    item.desc = value;
  } else {
    item.qty = field === 'qty' ? (parseFloat(value) || 0) : item.qty;
    item.price = field === 'price' ? (parseFloat(value) || 0) : item.price;
    // Only update the line total display without re-rendering the entire form
    const lineTotal = document.getElementById('line-total-' + id);
    if (lineTotal) lineTotal.value = (item.qty * item.price).toFixed(3);
  }
  // Never call renderInvoiceItemsForm() here — it destroys focus
  updateInvoicePreview();
}

function calcInvoiceAmounts() {
  const subtotal = invoiceItems.reduce((sum, it) => sum + (it.qty * it.price), 0);
  const vatRate = parseFloat(document.getElementById('invVatRate').value) || 0;
  const vat = subtotal * (vatRate / 100);
  const total = subtotal + vat;
  return { subtotal, vat, total, vatRate };
}

