const ONES_EN = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten',
  'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen'];
const TENS_EN = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

function numToWordsEN(num) {
  if (num === 0) return 'Zero';
  function chunk(n) {
    let s = '';
    if (n >= 100) { s += ONES_EN[Math.floor(n / 100)] + ' Hundred '; n %= 100; }
    if (n >= 20) { s += TENS_EN[Math.floor(n / 10)] + ' '; n %= 10; }
    if (n > 0) { s += ONES_EN[n] + ' '; }
    return s.trim();
  }
  const units = ['', ' Thousand', ' Million', ' Billion'];
  let parts = [];
  let i = 0;
  while (num > 0) {
    const rem = num % 1000;
    if (rem) parts.unshift(chunk(rem) + units[i]);
    num = Math.floor(num / 1000);
    i++;
  }
  return parts.join(' ').trim();
}

const ONES_AR = ['', 'واحد', 'اثنان', 'ثلاثة', 'أربعة', 'خمسة', 'ستة', 'سبعة', 'ثمانية', 'تسعة', 'عشرة',
  'أحد عشر', 'اثنا عشر', 'ثلاثة عشر', 'أربعة عشر', 'خمسة عشر', 'ستة عشر', 'سبعة عشر', 'ثمانية عشر', 'تسعة عشر'];
const TENS_AR = ['', '', 'عشرون', 'ثلاثون', 'أربعون', 'خمسون', 'ستون', 'سبعون', 'ثمانون', 'تسعون'];
const HUNDREDS_AR = ['', 'مائة', 'مئتان', 'ثلاثمائة', 'أربعمائة', 'خمسمائة', 'ستمائة', 'سبعمائة', 'ثمانمائة', 'تسعمائة'];

function numToWordsAR(num) {
  if (num === 0) return 'صفر';
  function chunk(n) {
    let parts = [];
    if (n >= 100) { parts.push(HUNDREDS_AR[Math.floor(n / 100)]); n %= 100; }
    if (n >= 20) {
      const t = Math.floor(n / 10), o = n % 10;
      if (o > 0) parts.push(ONES_AR[o] + ' و' + TENS_AR[t]);
      else parts.push(TENS_AR[t]);
    } else if (n > 0) {
      parts.push(ONES_AR[n]);
    }
    return parts.join(' و');
  }
  const units = ['', ' ألف', ' مليون', ' مليار'];
  let parts = [];
  let i = 0;
  while (num > 0) {
    const rem = num % 1000;
    if (rem) parts.unshift(chunk(rem) + units[i]);
    num = Math.floor(num / 1000);
    i++;
  }
  return parts.join(' و');
}

const CURRENCY_NAMES = {
  'R.O.': { en: ['Rial', 'Rials'], ar: 'ريال عماني', minorEn: ['Baisa', 'Baisa'], minorAr: 'بيسة', minorDiv: 1000 },
  '$': { en: ['Dollar', 'Dollars'], ar: 'دولار', minorEn: ['Cent', 'Cents'], minorAr: 'سنت', minorDiv: 100 },
  '€': { en: ['Euro', 'Euros'], ar: 'يورو', minorEn: ['Cent', 'Cents'], minorAr: 'سنت', minorDiv: 100 },
  '£': { en: ['Pound', 'Pounds'], ar: 'جنيه إسترليني', minorEn: ['Pence', 'Pence'], minorAr: 'بنس', minorDiv: 100 },
  'AED': { en: ['Dirham', 'Dirhams'], ar: 'درهم إماراتي', minorEn: ['Fils', 'Fils'], minorAr: 'فلس', minorDiv: 100 },
  'SAR': { en: ['Riyal', 'Riyals'], ar: 'ريال سعودي', minorEn: ['Halala', 'Halalas'], minorAr: 'هللة', minorDiv: 100 },
  '₹': { en: ['Rupee', 'Rupees'], ar: 'روبية', minorEn: ['Paisa', 'Paisa'], minorAr: 'بيسة', minorDiv: 100 }
};

function amountToWords(amount, sym, isAr) {
  const cur = CURRENCY_NAMES[sym] || CURRENCY_NAMES['R.O.'];
  const whole = Math.floor(amount);
  const minorDiv = cur.minorDiv;
  const minor = Math.round((amount - whole) * minorDiv);

  if (isAr) {
    const wholeWords = numToWordsAR(whole);
    let result = `${wholeWords} ${cur.ar}`;
    if (minor > 0) {
      result += ` و${numToWordsAR(minor)} ${cur.minorAr}`;
    }
    return result + ' فقط لا غير';
  } else {
    const wholeWords = numToWordsEN(whole) || 'Zero';
    const curLabel = whole === 1 ? cur.en[0] : cur.en[1];
    let result = `${wholeWords} ${curLabel}`;
    if (minor > 0) {
      const minorLabel = minor === 1 ? cur.minorEn[0] : cur.minorEn[1];
      result += ` and ${numToWordsEN(minor)} ${minorLabel}`;
    }
    return result + ' Only';
  }
}


