function exportPDF() {
  const el = document.getElementById('receiptPreview').firstElementChild;
  if (!el) return;
  doExportPDF(el);
}

function doExportPDF(el) {
  const recNum = document.getElementById('recNum').value || 'RV';
  showToast(currentLang === 'ar' ? 'جاري إنشاء PDF…' : 'Generating PDF…');

  let settled = false;
  const timeoutId = setTimeout(() => {
    if (!settled) {
      settled = true;
      showToast(currentLang === 'ar' ? 'فشل إنشاء PDF — حاول مجدداً' : 'PDF generation timed out — try again');
    }
  }, 12000);

  html2canvas(el, { scale: 2.5, useCORS: true, allowTaint: true, backgroundColor: '#ffffff', logging: false })
    .then(canvas => {
      if (settled) return;
      settled = true; clearTimeout(timeoutId);
      finalizePDF(canvas, recNum);
    })
    .catch(err => {
      settled = true; clearTimeout(timeoutId);
      console.error('html2canvas error:', err);
      showToast(currentLang === 'ar' ? 'فشل إنشاء PDF' : 'PDF generation failed — please try again');
    });
}

function finalizePDF(canvas, recNum) {
  const { jsPDF } = window.jspdf;
  const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  const pw = pdf.internal.pageSize.getWidth();   // 210mm
  const ph = pdf.internal.pageSize.getHeight();  // 297mm
  const imgData = canvas.toDataURL('image/jpeg', 0.97);
  // Force fill entire A4 page — stretch to fit, no blank space
  pdf.addImage(imgData, 'JPEG', 0, 0, pw, ph);
  const filename = `${settings.compEN.replace(/\s+/g, '_')}_${recNum}.pdf`;
  downloadPDFBlob(pdf, filename);
}

function downloadPDFBlob(pdf, filename) {
  try {
    const blob = pdf.output('blob');
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 4000);
    showToast(currentLang === 'ar' ? 'تم تحميل PDF ✓' : 'PDF downloaded ✓');
  } catch (e) {
    // Last resort: open in new tab so the user can manually save (Ctrl+S)
    try {
      const blob = pdf.output('blob');
      const url = URL.createObjectURL(blob);
      window.open(url, '_blank');
      showToast(currentLang === 'ar' ? 'افتح في تبويب جديد واحفظ يدوياً' : 'Opened in new tab — save manually (Ctrl+S)');
    } catch (e2) {
      showToast(currentLang === 'ar' ? 'فشل التحميل' : 'Download failed — try a different browser');
    }
  }
}

