// ── HISTORY ──
function renderHistory() {
  const container = document.getElementById('historyList');
  if (!receipts.length) {
    container.innerHTML = `<div class="history-empty">${currentLang === 'ar' ? 'لا توجد سجلات محفوظة بعد.' : 'No records saved yet.'}</div>`;
    return;
  }
  container.innerHTML = receipts.map((r, i) => {
    const isInvoice = r.type === 'invoice';
    const typeLabel = isInvoice ? (currentLang === 'ar' ? 'فاتورة' : 'Invoice') : (currentLang === 'ar' ? 'إيصال' : 'Receipt');
    const subLine = isInvoice ? r.date : `${r.date} · ${r.payMethod}`;
    return `
    <div class="history-item">
      <div class="history-item-info">
        <div class="history-item-num">${r.num} <span class="hist-type-badge">${typeLabel}</span></div>
        <div class="history-item-client">${r.client}</div>
        <div class="history-item-date">${subLine}</div>
      </div>
      <div class="history-item-total">${r.sym} ${r.total.toFixed(3)}</div>
      <div class="history-item-actions">
        <button class="hist-btn hist-btn-print" onclick="reprintFromHistory(${i})">${currentLang === 'ar' ? 'طباعة' : 'Print'}</button>
        <button class="hist-btn hist-btn-del" onclick="deleteReceipt(${i})">${currentLang === 'ar' ? 'حذف' : 'Delete'}</button>
      </div>
    </div>`;
  }).join('');
}

function deleteReceipt(i) {
  receipts.splice(i, 1);
  localStorage.setItem('ao_receipts', JSON.stringify(receipts));
  renderHistory();
  showToast(currentLang === 'ar' ? 'تم الحذف' : 'Deleted');
}

function reprintFromHistory(i) {
  const r = receipts[i];
  if (r.type === 'invoice') {
    document.getElementById('invNum').value = r.num;
    document.getElementById('invDate').value = r.date;
    document.getElementById('invDueDate').value = r.dueDate || '';
    document.getElementById('invClientName').value = r.client;
    document.getElementById('invVatRate').value = r.vatRate != null ? r.vatRate : 5;
    document.getElementById('invStamp').value = r.stamp;
    document.getElementById('invCurrency').value = r.sym;
    invoiceItems = (r.items || []).map(it => ({ id: newInvoiceItemId(), desc: it.desc, qty: it.qty, price: it.price }));
    if (invoiceItems.length === 0) invoiceItems = [{ id: newInvoiceItemId(), desc: '', qty: 1, price: 0 }];
    renderInvoiceItemsForm();
    updateInvoicePreview();
    showPage('new-invoice', document.querySelector('.nav-item[data-page="new-invoice"]'));
    setTimeout(() => printInvoice(), 400);
  } else {
    document.getElementById('recNum').value = r.num;
    document.getElementById('recDate').value = r.date;
    document.getElementById('clientName').value = r.client;
    document.getElementById('description').value = r.description;
    document.getElementById('amount').value = r.amount;
    document.getElementById('vatRate').value = r.vatRate != null ? r.vatRate : 5;
    document.getElementById('stamp').value = r.stamp;
    document.getElementById('currency').value = r.sym;
    updatePreview();
    showPage('new-receipt', document.querySelector('.nav-item[data-page="new-receipt"]'));
    setTimeout(() => printReceipt(), 400);
  }
}

